/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const N = nums.length;
    const INF = Number.MAX_SAFE_INTEGER;

    if (k === 0) {
        return 0;
    }

    // 1. Check Impossibility
    if (k > Math.floor(N / 2)) {
        return -1;
    }

    // Helper function for linear DP (Minimum Weight Independent Set of size K)
    // costs: array of costs C_i for the sequence being analyzed.
    // N_seq: length of the sequence.
    // K_target: number of peaks we need to select.
    function run_linear_dp(costs, N_seq, K_target) {
        if (K_target < 0) return INF;
        if (K_target === 0) return 0;
        if (N_seq === 0) return INF;

        // DP[i][j][s]: min cost considering first i+1 elements (0..i), selecting j items.
        // s=0: element i is NOT selected. s=1: element i IS selected.

        // Initialize DP table (N_seq) x (K_target + 1) x 2
        const DP = Array(N_seq).fill(0).map(() => 
            Array(K_target + 1).fill(0).map(() => [INF, INF])
        );

        // Base Case i = 0
        // 0 selected: cost 0
        DP[0][0][0] = 0;

        // 0 selected: cost C_0
        if (K_target >= 1) {
            DP[0][1][1] = costs[0];
        }

        // Transitions i = 1 to N_seq - 1
        for (let i = 1; i < N_seq; i++) {
            for (let j = 0; j <= K_target; j++) {

                // State 0: Element i is NOT selected
                // Comes from i-1 selected or i-1 unselected
                DP[i][j][0] = Math.min(DP[i-1][j][0], DP[i-1][j][1]);

                // State 1: Element i IS selected
                if (j >= 1) {
                    // Must come from i-1 NOT selected
                    const cost_if_selected = DP[i-1][j-1][0] + costs[i];
                    DP[i][j][1] = cost_if_selected;
                }
            }
        }

        // Final result: Min cost at the end of the sequence, achieving K_target peaks
        const result = Math.min(DP[N_seq - 1][K_target][0], DP[N_seq - 1][K_target][1]);
        return result;
    }

    // 2. Calculate Circular Costs C_i
    const C = new Array(N);
    for (let i = 0; i < N; i++) {
        const prev = nums[(i - 1 + N) % N];
        const next = nums[(i + 1) % N];
        const required = Math.max(prev, next) + 1;
        const cost = Math.max(0, required - nums[i]);
        C[i] = cost;
    }

    let min_total_cost = INF;

    // --- Case 1: nums[0] is NOT a peak. Target K peaks from indices 1 to N-1. ---
    if (N > 1) {
        // Sequence costs C[1] to C[N-1]. Length N-1.
        const costs_case1 = C.slice(1);
        const cost1 = run_linear_dp(costs_case1, N - 1, k);
        min_total_cost = Math.min(min_total_cost, cost1);
    } else if (N === 1 && k === 1) {
        // N=1 case is excluded by constraints (N>=2), but handled defensively.
    }


    // --- Case 2: nums[0] IS a peak. Target K-1 additional peaks from indices 2 to N-2. ---
    if (k >= 1) {
        let cost2 = C[0]; // Cost for making 0 a peak
        let N_seq_case2 = 0;
        let costs_case2 = [];

        if (N >= 3) {
            // Sequence costs C[2] to C[N-2]. Length N-3.
            N_seq_case2 = N - 3;
            costs_case2 = C.slice(2, N - 1); 

            const remaining_cost = run_linear_dp(costs_case2, N_seq_case2, k - 1);

            if (remaining_cost !== INF) {
                cost2 += remaining_cost;
                min_total_cost = Math.min(min_total_cost, cost2);
            }
        } else if (N === 2 && k === 1) {
            // N=2. 0 is peak. Neighbors 1, 1. Sequence is empty (N-3 = -1, handled by DP logic for empty seq)
            // Target k-1 = 0. DP returns 0. Cost is just C[0].
            cost2 = C[0];
            min_total_cost = Math.min(min_total_cost, cost2);
        }
    }


    return min_total_cost === INF ? -1 : min_total_cost;
}

